# Stage 1 — Replace kz+in with zh+ar, fix 3 middleware/switcher bugs, add geo-detection, RTL for Arabic

## Why this will be good
Three bugs today make language switching a frustrating dead-end: English users geo-redirected to Russian can't escape, clicking a language does nothing, and shared URLs 404. After this stage, language selection is instant (router.replace, no full reload), persistent (cookie always written including for English), geo-aware (MENA → Arabic, CN/TW/HK → Chinese, Russian-speaking countries → Russian), and Arabic renders RTL natively. Production-ready checklist: cookie written on every switch, middleware skips pre-prefixed URLs, broken locales (kz/in) are deleted not just hidden, Arabic pages flip via <html dir='rtl'> at the browser level (no per-component RTL work), translations are complete for every key in en.json so no string falls back untranslated.

## Files to touch (exact list)

**Create:**
- `messages/zh.json` — Chinese translations (content provided below)
- `messages/ar.json` — Arabic translations (content provided below)

**Delete:**
- `messages/kz.json`
- `messages/in.json`

**Edit:**
- `src/i18n/routing.ts` — swap locales array
- `src/middleware.ts` — rewrite GEO_LOCALE_MAP, fix hasLocalePrefix regex, fix ordering, always write cookie
- `src/components/Navbar.tsx` — update LANGUAGES_LIST, rewrite switchLocale
- `src/app/[locale]/layout.tsx` — add `dir` attribute on `<html>`
- `messages/en.json` — update `lang` section
- `messages/ru.json` — update `lang` section

## Exact changes

### 1. `src/i18n/routing.ts` — FULL REPLACE
```ts
import { defineRouting } from "next-intl/routing";

export const routing = defineRouting({
  locales: ["en", "ru", "zh", "ar"],
  defaultLocale: "en",
  localePrefix: "as-needed", // English: /about — Others: /ru/about, /zh/about, /ar/about
});
```

### 2. `src/middleware.ts` — FULL REPLACE
```ts
import createMiddleware from "next-intl/middleware";
import { routing } from "@/i18n/routing";
import { type NextRequest, NextResponse } from "next/server";

// Maps Vercel's 2-letter country code -> our locale
const GEO_LOCALE_MAP: Record<string, string> = {
  // Chinese
  CN: "zh",
  TW: "zh",
  HK: "zh",
  // Russian-speaking countries
  RU: "ru",
  BY: "ru",
  KZ: "ru",
  UA: "ru",
  KG: "ru",
  MD: "ru",
  TJ: "ru",
  UZ: "ru",
  AM: "ru",
  AZ: "ru",
  // MENA / Gulf -> Arabic
  AE: "ar",
  SA: "ar",
  EG: "ar",
  QA: "ar",
  KW: "ar",
  BH: "ar",
  OM: "ar",
  JO: "ar",
  LB: "ar",
  IQ: "ar",
  SY: "ar",
  YE: "ar",
  LY: "ar",
  TN: "ar",
  DZ: "ar",
  MA: "ar",
};

const LOCALE_COOKIE = "BINAYAH_LOCALE";
const COOKIE_MAX_AGE = 60 * 60 * 24 * 365; // 1 year
const intlMiddleware = createMiddleware(routing);

// Only non-default locales appear as URL prefixes (localePrefix: 'as-needed')
const LOCALE_PREFIX_REGEX = /^\/(ru|zh|ar)(\/|$)/;

function setLocaleCookie(response: NextResponse, locale: string) {
  response.cookies.set(LOCALE_COOKIE, locale, {
    maxAge: COOKIE_MAX_AGE,
    path: "/",
    sameSite: "lax",
  });
}

export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;

  // Skip static files and Next.js internals
  if (
    pathname.startsWith("/_next") ||
    pathname.startsWith("/api") ||
    pathname.match(/\.(ico|png|jpg|svg|webp|woff2?)$/)
  ) {
    return NextResponse.next();
  }

  // 1) URL already carries an explicit non-default locale prefix.
  //    Honor it, save the cookie, and LET next-intl handle it.
  //    This MUST run before the saved-locale redirect so that visiting
  //    /ru/foo while cookie=en does not ping-pong, and so that shared
  //    URLs like /zh/projects/sensia never get double-prefixed.
  const prefixMatch = pathname.match(LOCALE_PREFIX_REGEX);
  if (prefixMatch) {
    const matchedLocale = prefixMatch[1];
    const response = intlMiddleware(request);
    setLocaleCookie(response, matchedLocale);
    return response;
  }

  // 2) No URL prefix -> English is the intended locale for this path.
  //    If user has a saved non-English preference, redirect them to /<locale><path>.
  //    If saved preference is 'en' (explicit choice), honor it and DO NOT geo-redirect.
  const savedLocale = request.cookies.get(LOCALE_COOKIE)?.value;

  if (savedLocale === "en") {
    // User explicitly chose English — fall through to intlMiddleware, refresh cookie.
    const response = intlMiddleware(request);
    setLocaleCookie(response, "en");
    return response;
  }

  if (savedLocale && savedLocale !== "en" && routing.locales.includes(savedLocale as (typeof routing.locales)[number])) {
    const url = request.nextUrl.clone();
    url.pathname = `/${savedLocale}${pathname === "/" ? "" : pathname}`;
    return NextResponse.redirect(url);
  }

  // 3) First visit, no cookie -> geo-detect.
  const country = request.headers.get("x-vercel-ip-country") ?? "";
  const geoLocale = GEO_LOCALE_MAP[country.toUpperCase()];

  if (geoLocale && geoLocale !== "en") {
    const url = request.nextUrl.clone();
    url.pathname = `/${geoLocale}${pathname === "/" ? "" : pathname}`;
    const response = NextResponse.redirect(url);
    setLocaleCookie(response, geoLocale);
    return response;
  }

  // 4) Default: English. Write cookie so we do not geo-detect again next request.
  const response = intlMiddleware(request);
  setLocaleCookie(response, "en");
  return response;
}

export const config = {
  matcher: [
    "/((?!_next|_vercel|.*\\..*).*)",
  ],
};
```

### 3. `src/components/Navbar.tsx`

**Replace `LANGUAGES_LIST` constant (around line 18-23) with:**
```tsx
const LANGUAGES_LIST = [
  { code: "en", label: "English", flag: "🇬🇧" },
  { code: "ru", label: "Русский", flag: "🇷🇺" },
  { code: "zh", label: "中文", flag: "🇨🇳" },
  { code: "ar", label: "العربية", flag: "🇦🇪" },
];
```

**Replace entire `switchLocale` function (lines 112-123) with:**
```tsx
  const switchLocale = (locale: string) => {
    setShowLangDropdown(false);
    setMobileOpen(false);
    // Persist the choice BEFORE navigation so middleware honors it immediately.
    // max-age = 1 year, path=/ so every route sees it.
    document.cookie = `BINAYAH_LOCALE=${locale}; path=/; max-age=${60 * 60 * 24 * 365}; samesite=lax`;
    // next-intl router.replace with {locale} handles prefix add/strip correctly
    // and does not produce /xx/yy double-prefixes because `pathname` from
    // next-intl's usePathname is already locale-stripped.
    router.replace(pathname, { locale });
  };
```

> DEV note: `router` and `pathname` are already imported from `@/navigation` at the top of the file (lines 5 and 27-28). Do NOT add next/navigation imports — `@/navigation` already provides the correct locale-aware hooks. The `useRouter` hook from `@/navigation` returns a router whose `.replace()` accepts a second arg `{ locale }` per next-intl's typing.

### 4. `src/app/[locale]/layout.tsx`

Change the `<html>` opening tag (around line 77-81). Current:
```tsx
