      lang={locale}
      suppressHydrationWarning
      className={`${jakarta.variable} ${playfair.variable}`}
    >
```
Replace with:
```tsx
    <html
      lang={locale}
      dir={locale === "ar" ? "rtl" : "ltr"}
      suppressHydrationWarning
      className={`${jakarta.variable} ${playfair.variable}`}
    >
```

